function queryFields(query, document) {
  if (Object.keys(query).length === 0) return document;
  for (let field in query) {
    if (document[field] !== undefined && document[field] !== null && document[field] === query[field]) {
      console.log(field, document[field]);
    }
  }
  return {};
}

